  ('locality-6e2f88c7-moex-00115', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '有關行政處分無效事由之敘述，下列何者錯誤？', '["未經授權而違背法規有關管轄之規定，主要係指欠缺事物管轄及土地管轄之情形", "所要求或許可之行為構成犯罪者，係指該行為客觀上違反刑罰之法規，而具有違法性", "應以證書方式作成而未給予證書者，係指凡行政處分應依法定方式作成而有所欠缺者", "不能得知處分機關，係指經由形式觀察，無法得知處分機關之情形"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "3f3af846f323", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
